python_example:
import httpx

client = httpx.Client(base_url="https://api.cargohive.io/v2")
response = client.post(
    "/inventory/search",
    params={"page": 1, "per_page": 50},
    headers={
        "Authorization": "Bearer <token>",
        "X-Warehouse-Region": "US",
    },
    json={
        "query": "lithium battery pack 48V",
        "filters": {"category": "electronics", "min_quantity": 10},
    },
)
data = response.json()
for item in data["results"]:
    print(f"{item['sku']}  qty={item['quantity_on_hand']}  bin={item['bin_location']}")

javascript_example:
const res = await fetch(
  "https://api.cargohive.io/v2/inventory/search?page=1&per_page=50",
  {
    method: "POST",
    headers: {
      "Authorization": "Bearer <token>",
      "Content-Type": "application/json",
      "X-Warehouse-Region": "US"
    },
    body: JSON.stringify({
      query: "lithium battery pack 48V",
      filters: { category: "electronics", min_quantity: 10 }
    })
  }
);
const data = await res.json();
console.log(`Found ${data.total} items`);
data.results.forEach(r => console.log(`${r.sku}: ${r.quantity_on_hand} units`));
